class RangeModule {

    public RangeModule() {

    }

    public void addRange(int left, int right) {
        int index = binarySearch(left);
        if (index == size || intervals[index] > left) {
            intervals = Arrays.copyOf(intervals, size + 1);
            intervals[size] = left;
            size++;
        }
        if (index == 0 || intervals[index - 1] <= right) {
            if (index == 0 || intervals[index - 1] < right) {
                intervals[index - 1] = Math.min(intervals[index - 1], right);
            }
            if (index == size || intervals[index] > right) {
                intervals[index] = Math.max(intervals[index], right);
            }
        } else {
            intervals[index - 1] = Math.min(intervals[index - 1], right);
            intervals[index] = Math.max(intervals[index], right);
        }
    }

    public boolean queryRange(int left, int right) {
        int index = binarySearch(left);
        if (index == size || intervals[index] > right) {
            return false;
        }
        return true;
    }

    public void removeRange(int left, int right) {
        int index = binarySearch(left);
        while (index < size && intervals[index] <= right) {
            if (index > 0 && intervals[index - 1] <= right) {
                intervals[index - 1] = Math.min(intervals[index - 1], intervals[index]);
            }
            if (index + 1 < size && intervals[index + 1] <= right) {
                intervals[index] = Math.max(intervals[index], intervals[index + 1]);
            }
            if (index > 0 && intervals[index - 1] == intervals[index]) {
                size--;
                for (int i = index; i < size; i++) {
                    intervals[i] = intervals[i + 1];
                }
            } else {
                index++;
            }
        }
    }

    private int binarySearch(int target) {
        int left = 0, right = size;
        while (left < right) {
            int mid = left + (right - left) / 2;
            if (intervals[mid] < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    }

    private int[] intervals;
    private int size;
}
